import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Aktualizowanie Fabric","description":"Przewodnik krok po kroku o tym, jak zaktualizować Fabric.","frontmatter":{"title":"Aktualizowanie Fabric","description":"Przewodnik krok po kroku o tym, jak zaktualizować Fabric.","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"pl_pl/1.21.10/players/updating-fabric.md","filePath":"versions/1.21.10/translated/pl_pl/players/updating-fabric.md","lastUpdated":1766682904000}`);var c={name:`pl_pl/1.21.10/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Aktualizowanie Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Aktualizowanie Fabric”">​</a></h1><p>Ten przewodnik pokaże ci, jak zaktualizować Fabric dla oficjalnego launchera Minecrafta.</p><p>W przypadku innych launcherów należy zapoznać się z ich dokumentacją.</p><p>Aktualizowanie Fabric jest procesem bardzo podobnym do jego instalowania, więc część tego przewodnika będzie taka sama jak w przypadku przewodnika do <a href="./installing-fabric">instalowania Fabric</a>.</p><h2 id="why-should-i-update-fabric-loader" tabindex="-1">Dlaczego warto aktualizować Fabric Loadera? <a class="header-anchor" href="#why-should-i-update-fabric-loader" aria-label="Permalink to “Dlaczego warto aktualizować Fabric Loadera?”">​</a></h2><p>Nowsze mody mogą wymagać do działania nowszej wersji Fabric Loadera, więc ważne jest, aby go aktualizować, aby móc korzystać z najnowszych modów.</p><p>W przypadku innych launcherów należy zapoznać się z ich dokumentacją.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Pobierz instalator Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Pobierz instalator Fabric”">​</a></h2><p>Instalator Fabric możesz pobrać ze <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">strony Fabric</a>.</p><p>Jeśli korzystasz z systemu Windows, pobierz wersję <code>.exe</code> (<code>Download for Windows</code>), ponieważ nie wymaga ona posiadania zainstalowanej Javy. Zamiast tego wykorzystuje Javę, która jest dołączona w oficjalnym launcherze.</p><p>W przypadku systemów macOS i Linux należy pobrać wersję <code>.jar</code>. Czasami przed wykonaniem tego kroku konieczne jest zainstalowanie Javy.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Uruchom instalator Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Uruchom instalator Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Przed instalacją należy zamknąć Minecrafta, jak i jego launcher.</p></div><details class="details custom-block"><summary>Informacja dla użytkowników systemu macOS</summary><p>Na systemie macOS do uruchomienia pliku <code>.jar</code> może być konieczne kliknięcie go prawym przyciskiem myszy, a następnie wybranie opcji <code>Otwórz</code>.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Menu kontekstowe macOS z instalatorem Fabric" loading="lazy"></p><p>Gdy pojawi się komunikat „Czy na pewno chcesz otworzyć ten plik?”, ponownie kliknij <code>Otwórz</code>.</p></details><p>Po otworzeniu instalatora powinno pojawić się takie okno:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Instalator Fabric z wyróżnionym tekstem „Zainstaluj”" loading="lazy"></p><p>Aby zainstalować Fabric, wystarczy po prostu wybrać wersję gry z rozwijanej listy i kliknąć <code>Zainstaluj</code>.</p><p>Aby zaktualizować Fabric, wystarczy upewnić się, że wersje gry i Loadera są poprawne, a następnie kliknąć <code>Zainstaluj</code>.</p><div class="warning custom-block"><p class="custom-block-title">WAŻNE</p><p>Upewnij się, że opcja <code>Utwórz profil</code> jest odznaczona podczas uruchamiania instalatora, w przeciwnym razie zostanie utworzony nowy profil, którego w tym przypadku nie potrzebujemy.</p></div><h2 id="3-open-the-profile-in-the-minecraft-launcher" tabindex="-1">3. Otwórz profil w launcherze Minecrafta <a class="header-anchor" href="#3-open-the-profile-in-the-minecraft-launcher" aria-label="Permalink to “3. Otwórz profil w launcherze Minecrafta”">​</a></h2><p>Po zakończeniu instalacji możesz otworzyć launcher Minecrafta i przejść do zakładki <code>Instalacje</code>. Następnie przejdź do swojego profilu Fabric i otwórz ekran edycji.</p><p>Zastąp aktualnie wybraną wersję nowo zainstalowaną wersją Fabric Loadera i naciśnij <code>Zapisz</code>.</p><p><img src="/assets/players/updating-fabric.png" alt="Aktualizowanie wersji Fabric Loadera w launcherze Minecrafta" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. I to tyle! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. I to tyle!”">​</a></h2><p>Po wykonaniu wszystkich kroków możesz z powrotem przejść do zakładki <code>Graj</code>, wybrać z rozwijanej listy w lewym dolnym rogu profil Fabric, a następnie zacząć grać!</p><p>Jeśli napotkasz jakiś problem podczas korzystania z tego przewodnika, możesz poprosić o pomoc na <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discordzie Fabric</a> na kanale <code>#player-support</code>.</p>`,26)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};